public class ThreadCreationExample {
    public static void main(String[] args) {
        System.out.println("Main thread starting...");

        // 1. Extending Thread class
        System.out.println("=== Extending Thread ===");
        MyThread thread1 = new MyThread("Thread-1");
        thread1.start();  // NOT run()!

        // 2. Implementing Runnable
        System.out.println("=== Implementing Runnable ===");
        MyRunnable runnable = new MyRunnable("Thread-2");
        Thread thread2 = new Thread(runnable);
        thread2.start();

        // 3. Lambda (Java 8+)
        System.out.println("=== Lambda Runnable ===");
        Thread thread3 = new Thread(() -> {
            for (int i = 1; i <= 3; i++) {
                System.out.println("Lambda-Thread: " + i);
                sleep(100);
            }
        });
        thread3.start();

        // 4. Multiple threads
        System.out.println("=== Multiple Threads ===");
        for (int i = 0; i < 3; i++) {
            Thread t = new Thread(() -> {
                System.out.println("Thread " + Thread.currentThread().getName() + " running");
            });
            t.setName("Worker-" + i);
            t.start();
        }

        // 5. Thread methods
        System.out.println("=== Thread Methods ===");
        Thread thread4 = new Thread(() -> {
            System.out.println("Thread " + Thread.currentThread().getName() + " is running");
        });
        thread4.setName("MyThread");
        thread4.setPriority(Thread.MAX_PRIORITY);  // 1-10
        System.out.println("Name: " + thread4.getName());
        System.out.println("Priority: " + thread4.getPriority());
        System.out.println("State: " + thread4.getState());
        thread4.start();
        System.out.println("State after start: " + thread4.getState());

        // 6. Daemon threads
        System.out.println("=== Daemon Thread ===");
        Thread daemon = new Thread(() -> {
            for (int i = 0; i < 10; i++) {
                System.out.println("Daemon: " + i);
                sleep(50);
            }
        });
        daemon.setDaemon(true);  // Program exits without waiting for daemon
        daemon.start();

        // Main thread continues
        System.out.println("Main thread ending...");
    }

    static void sleep(long ms) {
        try {
            Thread.sleep(ms);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }
}

// Method 1: Extend Thread
class MyThread extends Thread {
    MyThread(String name) {
        super(name);
    }

    @Override
    public void run() {
        for (int i = 0; i < 3; i++) {
            System.out.println(getName() + ": " + i);
            try {
                Thread.sleep(200);
            } catch (InterruptedException e) {
                System.out.println(getName() + " interrupted");
            }
        }
        System.out.println(getName() + " finished");
    }
}

// Method 2: Implement Runnable
class MyRunnable implements Runnable {
    private String name;

    MyRunnable(String name) {
        this.name = name;
    }

    @Override
    public void run() {
        for (int i = 0; i < 3; i++) {
            System.out.println(name + ": " + i);
            try {
                Thread.sleep(150);
            } catch (InterruptedException e) {
                System.out.println(name + " interrupted");
            }
        }
        System.out.println(name + " finished");
    }
}

